import{_ as e,c as o,o as d,ah as r}from"./chunks/framework.RCw5T9E9.js";const p=JSON.parse('{"title":"Расширенный режим захвата (Advanced mode)","description":"","frontmatter":{"title":"Расширенный режим захвата (Advanced mode)"},"headers":[],"relativePath":"ru/network/advanced.md","filePath":"ru/network/advanced.md"}'),n={name:"ru/network/advanced.md"};function a(s,t,c,l,g,i){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="расширенныи-режим-захвата-advanced-mode" tabindex="-1">Расширенный режим захвата (Advanced mode) <a class="header-anchor" href="#расширенныи-режим-захвата-advanced-mode" aria-label="Permalink to &quot;Расширенный режим захвата (Advanced mode)&quot;">​</a></h1><p>В разделе <strong>Options → Network</strong> можно выбрать <strong>режим захвата</strong> сетевого обмена:</p><table tabindex="0"><thead><tr><th>Режим</th><th>В интерфейсе</th><th>Суть</th></tr></thead><tbody><tr><td><strong>Classic mode</strong></td><td>«классический» снимок</td><td>Те же ограничения, что у перехвата на странице: видны заголовки и тело в объёме, доступном скрипту страницы (в т.ч. правила <strong>CORS</strong> для чужого origin). Подробнее см. <a href="./general.html#ограничения-отображения">Работа с запросами</a>.</td></tr><tr><td><strong>Advanced mode</strong></td><td>расширенный захват</td><td>Расширение запрашивает доступ к <strong><code>webRequest</code></strong> и дополняет карточку запроса <strong>полным набором заголовков</strong> запроса и ответа так, как их видит браузер на уровне обмена, а не только «разрешённый странице» список.</td></tr></tbody></table><p><strong>Advanced mode</strong> (закрепление заголовков, <strong>Header links</strong>, опции <strong>Advanced headers</strong>) доступен <strong>только в расширении</strong> для Chrome / Edge.<br><strong>В Standalone</strong> по-прежнему используется сценарий без расширенного захвата: полный набор заголовков через <strong><code>webRequest</code></strong>, описанный ниже, там <strong>недоступен</strong>.</p><hr><h2 id="что-дает-advanced-mode-во-вкладке-network" tabindex="-1">Что даёт Advanced mode во вкладке Network <a class="header-anchor" href="#что-дает-advanced-mode-во-вкладке-network" aria-label="Permalink to &quot;Что даёт Advanced mode во вкладке Network&quot;">​</a></h2><ul><li><strong>Заголовки запроса и ответа</strong> в детализации запроса отражают расширенные данные (в том числе служебные и не попавшие в <code>Access-Control-Expose-Headers</code>).</li><li><strong>Закрепление строк заголовков (pin)</strong> — для имени заголовка можно закрепить строку <strong>вверху списка</strong> отдельно для блока <strong>Request</strong> и отдельно для <strong>Response</strong>. Закрепления выполняются из <strong>меню строки</strong> заголовка (три точки) при активном Advanced mode.</li><li><strong>Header links</strong> — для пары «имя заголовка + <strong>Host</strong> запроса» задаётся шаблон внешнего URL; плейсхолдер <strong><code>{value}</code></strong> и при необходимости <strong>цепочка преобразований (pipeline)</strong> определяют, как текст заголовка попадает в ссылку. Подробнее в разделе <a href="#header-links">Header links</a>.</li></ul><p>Список <strong>Header links</strong>, таблица <strong>Pinned headers</strong> и блок <strong>Advanced headers</strong> в <strong>Options → Network</strong> отображаются <strong>только при включённом Advanced mode</strong>, чтобы не перегружать Classic mode.</p><hr><h2 id="header-links" tabindex="-1">Header links <a class="header-anchor" href="#header-links" aria-label="Permalink to &quot;Header links&quot;">​</a></h2><p>Правило задаёт:</p><ul><li><strong>Header</strong> — имя HTTP-заголовка (сопоставление <strong>без учёта регистра</strong>);</li><li><strong>Host</strong> — хост URL запроса (нормализуется, без схемы и пути, например <code>api.example.com</code>);</li><li><strong>Link</strong> — шаблон URL; подстановка описана в разделе <strong><a href="#value-placeholder-and-pipelines">плейсхолдер <code>{value}</code> и pipeline</a></strong>.</li></ul><p>Создание и правка правил доступны из <strong>меню строки заголовка</strong> во вкладке <strong>Network</strong> (Advanced) и из <strong>Options</strong> при выбранной группе правил для заголовка.</p><h3 id="value-placeholder-and-pipelines" tabindex="-1">Плейсхолдер <code>{value}</code> и pipeline <a class="header-anchor" href="#value-placeholder-and-pipelines" aria-label="Permalink to &quot;Плейсхолдер `{value}` и pipeline {#value-placeholder-and-pipelines}&quot;">​</a></h3><p>В поле <strong>Link</strong> можно использовать:</p><ul><li><strong><code>{value}</code></strong> — подставить значение заголовка <strong>как на карточке запроса</strong> (то же, что pipeline без шагов).</li><li><strong><code>{value|…}</code></strong> — <strong>цепочка операций</strong>: после <code>{value</code> перечислите шаги через <strong><code>|</code></strong>; они выполняются <strong>слева направо</strong>, в URL попадает итог. Пример: <code>{value|trim|urlencode}</code>.</li></ul><p>Между шагами — символ <strong><code>|</code></strong>. Разбор делит цепочку по <code>|</code> только если <strong>следующий</strong> фрагмент начинается с <strong>известной операции</strong> (см. таблицы ниже). Поэтому <code>|</code> <strong>внутри регулярного выражения</strong> (например, альтернация <code>a|b</code>) обычно допустим, пока после кандидата на разрез не получается «новое имя операции».</p><p>Если шаг некорректен (например, ошибка в regex), этот шаг <strong>пропускается</strong>, значение после него не меняется из-за этого шага.</p><h4 id="операции-без-аргументов" tabindex="-1">Операции без аргументов <a class="header-anchor" href="#операции-без-аргументов" aria-label="Permalink to &quot;Операции без аргументов&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Op</th><th>Действие</th></tr></thead><tbody><tr><td><code>trim</code></td><td>Убрать пробелы в начале и в конце.</td></tr><tr><td><code>lower</code> / <code>upper</code></td><td>Нижний / верхний регистр.</td></tr><tr><td><code>urlencode</code> / <code>urldecode</code></td><td>Кодирование для URL / обратное декодирование (<code>+</code> как пробел; неверные escape не ломают значение).</td></tr><tr><td><code>base64encode</code> / <code>base64decode</code></td><td>Base64 для UTF-8.</td></tr><tr><td><code>hexencode</code> / <code>hexdecode</code></td><td>Шестнадцатеричная строка ↔ UTF-8 (<code>hexdecode</code> игнорирует пробелы).</td></tr><tr><td><code>md5</code></td><td>MD5 в hex для UTF-8 (синхронно).</td></tr><tr><td><code>sha1</code> / <code>sha256</code></td><td>SHA-1 / SHA-256 в hex через <strong>Web Crypto</strong> (<code>crypto.subtle</code>). Нужен контекст с доступным SubtleCrypto (например <strong>HTTPS</strong> или страницы расширения); иначе на шаге хеша получится пустая строка.</td></tr></tbody></table><h4 id="регулярные-выражения-и-замена" tabindex="-1">Регулярные выражения и замена <a class="header-anchor" href="#регулярные-выражения-и-замена" aria-label="Permalink to &quot;Регулярные выражения и замена&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Op</th><th>Синтаксис</th><th>Заметки</th></tr></thead><tbody><tr><td><code>regex</code></td><td><code>regex:&lt;pattern&gt;</code></td><td><code>new RegExp(&lt;pattern&gt;)</code> (отдельного поля для флагов нет — при необходимости см. возможности движка в самом шаблоне). Запоминает <strong>последнее совпадение</strong> для следующего <code>replace</code>. Нет совпадения → значение становится пустой строкой.</td></tr><tr><td><code>replace</code></td><td><code>replace:&lt;template&gt;</code></td><td>После <code>replace:</code> в шаблоне подставляются <strong><code>$1</code></strong>, <strong><code>$2</code></strong>, … из <strong>последнего</strong> <code>regex</code>. Без совпадения — пусто.</td></tr><tr><td><code>replaceRegex</code></td><td><code>replaceRegex:&lt;pattern&gt;:&lt;template&gt;</code></td><td><strong>Шаблон</strong> и <strong>паттерн</strong> отделяются по <strong>последнему</strong> <code>:</code> в сегменте; двоеточие внутри паттерна неудобно — лучше связка <strong><code>regex</code> + <code>replace</code></strong>.</td></tr><tr><td><code>match</code></td><td><code>match:&lt;pattern&gt;</code></td><td>Если значение подходит под шаблон — оставить; иначе заменить на пустую строку.</td></tr></tbody></table><h4 id="строки-и-структура" tabindex="-1">Строки и структура <a class="header-anchor" href="#строки-и-структура" aria-label="Permalink to &quot;Строки и структура&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Op</th><th>Синтаксис</th><th>Заметки</th></tr></thead><tbody><tr><td><code>replaceText</code></td><td><code>replaceText:&lt;from&gt;:&lt;to&gt;</code></td><td>По <strong>последнему</strong> <code>:</code> в аргументах отделяется <code>&lt;to&gt;</code>; слева — <code>&lt;from&gt;</code> (<code>from</code> может содержать <code>:</code>). Замена всех вхождений. Пустой <code>from</code> — шаг пропускается.</td></tr><tr><td><code>substring</code></td><td><code>substring:&lt;start&gt;</code> или <code>substring:&lt;start&gt;:&lt;length&gt;</code></td><td>Усечение строки: при двух числах <strong>длина</strong> — число символов от <code>start</code>.</td></tr><tr><td><code>split</code></td><td><code>split:&lt;delimiter&gt;:&lt;index&gt;</code></td><td><strong>Индекс</strong> — только цифры после <strong>последнего</strong> <code>:</code>; <strong>разделитель</strong> — всё до него (может содержать <code>:</code>). Вне диапазона — пусто.</td></tr></tbody></table><h4 id="условия-и-значения-по-умолчанию" tabindex="-1">Условия и значения по умолчанию <a class="header-anchor" href="#условия-и-значения-по-умолчанию" aria-label="Permalink to &quot;Условия и значения по умолчанию&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Op</th><th>Синтаксис</th><th>Заметки</th></tr></thead><tbody><tr><td><code>default</code></td><td><code>default:&lt;fallback&gt;</code></td><td>Если после предыдущих шагов значение <strong>строго пустая строка</strong> — подставить <code>&lt;fallback&gt;</code>. Пробелы «как пусто» — сначала <strong><code>trim</code></strong>.</td></tr><tr><td><code>ifMatch</code></td><td><code>ifMatch:&lt;pattern&gt;:&lt;ifTrue&gt;:&lt;ifFalse&gt;</code></td><td>Ветка <strong>false</strong> после <strong>последнего</strong> <code>:</code>; <strong>true</strong> — между <strong>предпоследним</strong> и <strong>последним</strong> <code>:</code>; <strong>pattern</strong> — всё до <strong>предпоследнего</strong> <code>:</code> (двоеточия внутри веток с этим правилом связаны).</td></tr></tbody></table><h3 id="примеры" tabindex="-1">Примеры <a class="header-anchor" href="#примеры" aria-label="Permalink to &quot;Примеры&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://trace.example.com/?id={value}</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://trace.example.com/?id={value|trim|urlencode}</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://trace.example.com/?t={value|regex:^Bearer\\s+(.+)$|replace:$1|urlencode}</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://trace.example.com/?t={value|default:unknown}</span></span></code></pre></div><p>В одном шаблоне можно несколько блоков <code>{value…}</code>; каждый считается от <strong>того же</strong> значения заголовка.</p><hr><h2 id="краткая-памятка" tabindex="-1">Краткая памятка <a class="header-anchor" href="#краткая-памятка" aria-label="Permalink to &quot;Краткая памятка&quot;">​</a></h2><ul><li><strong>Advanced mode</strong> расширяет заголовки за счёт <strong><code>webRequest</code></strong>; <strong>Standalone</strong> этого режима не предоставляет.</li><li><strong>Classic mode</strong> — прежняя модель «видимости» заголовков для страницы.</li><li><strong>Pin</strong> — отдельно для списков <strong>Request</strong> / <strong>Response</strong>.</li><li><strong>Header links:</strong> <strong>Host</strong> + шаблон <strong>Link</strong>: <strong><code>{value}</code></strong> или цепочка <strong><code>{value|op|…}</code></strong> для подстановки значения заголовка.</li></ul>',35)])])}const u=e(n,[["render",a]]);export{p as __pageData,u as default};
